// The AlphaZero training loop's data layer: self-play, a replay buffer, the train step, and
// evaluation against reference opponents.
//
// There is no dataset. A game is generated by the current network playing *itself* through MCTS;
// every position visited becomes a training example whose policy target is the search's visit
// distribution and whose value target is the game's eventual result (from that position's mover's
// perspective). The network trains on a moving window of recent self-play, then plays stronger
// self-play, and so on. Evaluation pits the (search-backed) network against a random player and a
// perfect / strong opponent so we can watch real skill appear — and, for Tic-Tac-Toe, assert the
// agent never loses to perfect play.

import { type Game, type GameState, type Player, solve, boundedSearch, type SolveResult } from './games';
import { AZNet, azLoss } from './aznet';
import { Optimizer, defaultOptimizer, clipGradGlobalNorm } from './optim';
import {
  runSearch,
  visitPolicy,
  sampleFrom,
  argmaxPolicy,
  type Evaluator,
  type MctsConfig,
} from './mcts';

// One self-play training example before the game outcome is known.
interface PendingExample {
  enc: Float64Array;
  mask: Float64Array;
  pi: Float64Array;
  player: Player;
}

export interface Example {
  enc: Float64Array; // [planes*cells]
  mask: Float64Array; // [numActions]
  pi: Float64Array; // [numActions] target visit distribution
  z: number; // outcome in {−1, 0, 1} from `player`'s perspective
}

// Wrap a network as an MCTS evaluator.
export function netEvaluator(net: AZNet, game: Game): Evaluator {
  return (s: GameState) => {
    const ev = net.evaluate(game.encode(s), game.legalMask(s));
    return { policy: ev.policy, value: ev.value };
  };
}

export interface SelfPlayConfig {
  mcts: MctsConfig;
  tempMoves: number; // opening plies played at exploration temperature (then greedy)
  temperature: number; // the exploration temperature for those opening plies
  augment: boolean; // expand each example by the game's board symmetries
}

export interface SelfPlayResult {
  examples: Example[];
  winner: number; // absolute winner of the generated game
  plies: number;
}

// Play one self-play game and return its (augmented) training examples.
export function playSelfPlayGame(net: AZNet, game: Game, cfg: SelfPlayConfig, rng: () => number): SelfPlayResult {
  const evaluate = netEvaluator(net, game);
  let s = game.initial();
  const pending: PendingExample[] = [];
  for (;;) {
    const st = game.status(s);
    if (st.done) {
      const examples = finalize(pending, st.winner, game, cfg.augment);
      return { examples, winner: st.winner, plies: s.ply };
    }
    const res = runSearch(game, s, evaluate, cfg.mcts, rng);
    // Training target: the search visit distribution (temperature 1 = counts normalized).
    const target = visitPolicy(res.counts, 1);
    pending.push({ enc: game.encode(s), mask: floatMask(game.legalMask(s)), pi: target, player: s.player });
    // Move selection: explore (sample at τ) for the opening, then play greedily.
    const tau = s.ply < cfg.tempMoves ? cfg.temperature : 0;
    const moveDist = visitPolicy(res.counts, tau);
    const a = tau > 0 ? sampleFrom(moveDist, rng) : argmaxPolicy(moveDist);
    s = game.apply(s, a);
  }
}

function floatMask(mask: Uint8Array): Float64Array {
  const out = new Float64Array(mask.length);
  for (let i = 0; i < mask.length; i++) out[i] = mask[i];
  return out;
}

// Attach the game outcome to each pending example (from its own mover's perspective) and, if
// requested, multiply the data by the game's board symmetries.
function finalize(pending: PendingExample[], winner: number, game: Game, augment: boolean): Example[] {
  const syms = augment ? game.symmetries() : [game.symmetries()[0]];
  const cells = game.cells;
  const planes = game.planes;
  const out: Example[] = [];
  for (const ex of pending) {
    const z = winner === 0 ? 0 : winner === ex.player ? 1 : -1;
    for (const sym of syms) {
      const enc = new Float64Array(planes * cells);
      for (let p = 0; p < planes; p++) {
        for (let i = 0; i < cells; i++) enc[p * cells + i] = ex.enc[p * cells + sym.cellPerm[i]];
      }
      const mask = new Float64Array(game.numActions);
      const pi = new Float64Array(game.numActions);
      for (let a = 0; a < game.numActions; a++) {
        mask[a] = ex.mask[sym.actPerm[a]];
        pi[a] = ex.pi[sym.actPerm[a]];
      }
      out.push({ enc, mask, pi, z });
    }
  }
  return out;
}

// --- Replay buffer (a ring of recent examples) --------------------------------------------------

export class ReplayBuffer {
  private buf: Example[] = [];
  private head = 0;
  readonly capacity: number;
  constructor(capacity: number) {
    this.capacity = capacity;
  }

  push(ex: Example): void {
    if (this.buf.length < this.capacity) this.buf.push(ex);
    else {
      this.buf[this.head] = ex;
      this.head = (this.head + 1) % this.capacity;
    }
  }
  pushAll(exs: Example[]): void {
    for (const e of exs) this.push(e);
  }
  get size(): number {
    return this.buf.length;
  }
  sample(n: number, rng: () => number): Example[] {
    const out: Example[] = [];
    if (this.buf.length === 0) return out;
    for (let i = 0; i < n; i++) out.push(this.buf[Math.floor(rng() * this.buf.length)]);
    return out;
  }
}

// --- Training step ------------------------------------------------------------------------------

export function makeOptimizer(net: AZNet, lr: number): Optimizer {
  return new Optimizer(net.parameters(), defaultOptimizer('adam', lr));
}

export interface TrainStepResult {
  policyLoss: number;
  valueLoss: number;
}

export function trainStep(
  net: AZNet,
  opt: Optimizer,
  batch: Example[],
  l2: number,
  clipNorm: number,
): TrainStepResult {
  const N = batch.length;
  const cfg = net.cfg;
  const cells = cfg.rows * cfg.cols;
  const A = cfg.numActions;
  const enc = new Float64Array(N * cfg.planes * cells);
  const mask = new Float64Array(N * A);
  const pi = new Float64Array(N * A);
  const z = new Float64Array(N);
  for (let i = 0; i < N; i++) {
    enc.set(batch[i].enc, i * cfg.planes * cells);
    mask.set(batch[i].mask, i * A);
    pi.set(batch[i].pi, i * A);
    z[i] = batch[i].z;
  }
  opt.zeroGrad();
  const parts = azLoss(net, enc, mask, pi, z, N, l2);
  parts.loss.backward();
  clipGradGlobalNorm(net.parameters(), clipNorm);
  opt.step();
  return { policyLoss: parts.policyLoss, valueLoss: parts.valueLoss };
}

// --- Evaluation ---------------------------------------------------------------------------------

export type OpponentKind = 'random' | 'perfect' | 'strong';

export interface EvalResult {
  games: number;
  wins: number;
  draws: number;
  losses: number;
  scoreRate: number; // (wins + 0.5·draws) / games
}

// A move from a reference opponent.
function opponentMove(
  game: Game,
  s: GameState,
  kind: OpponentKind,
  rng: () => number,
  memo: Map<string, SolveResult>,
  strongDepth: number,
): number {
  if (kind === 'random') {
    const m = game.legalMoves(s);
    return m[Math.floor(rng() * m.length)];
  }
  if (kind === 'perfect') return solve(game, s, memo).bestMove;
  return boundedSearch(game, s, strongDepth).bestMove;
}

// Play the (search-backed) network against a reference opponent for `games` games, alternating who
// starts, and tally results from the network's perspective.
export function evaluate(
  net: AZNet,
  game: Game,
  kind: OpponentKind,
  games: number,
  evalSims: number,
  cPuct: number,
  rng: () => number,
  strongDepth = 6,
): EvalResult {
  const evaluator = netEvaluator(net, game);
  const memo = new Map<string, SolveResult>();
  const mcts: MctsConfig = { simulations: evalSims, cPuct, dirichletAlpha: 0.3, dirichletFrac: 0 };
  let wins = 0;
  let draws = 0;
  let losses = 0;
  for (let g = 0; g < games; g++) {
    const netIsP1: boolean = g % 2 === 0;
    let s = game.initial();
    for (;;) {
      const st = game.status(s);
      if (st.done) {
        if (st.winner === 0) draws++;
        else if ((st.winner === 1) === netIsP1) wins++;
        else losses++;
        break;
      }
      const netToMove = (s.player === 1) === netIsP1;
      let a: number;
      if (netToMove) {
        const res = runSearch(game, s, evaluator, mcts, rng);
        a = argmaxPolicy(visitPolicy(res.counts, 0));
      } else {
        a = opponentMove(game, s, kind, rng, memo, strongDepth);
      }
      s = game.apply(s, a);
    }
  }
  return { games, wins, draws, losses, scoreRate: (wins + 0.5 * draws) / games };
}
